INSERT INTO public.treatments (slug, title, short_description, full_description, icon_name, display_order) VALUES
('lentes-de-porcelana', 'Lentes de Porcelana', 'Com atuação precisa e olhar estético apurado, o Dr. Márcio Pelegrina oferece lentes de porcelana para transformar sorrisos com naturalidade e sofisticação.', 'Lentes de porcelana são finas lâminas de cerâmica coladas à superfície dos dentes, proporcionando um sorriso harmonioso e natural. O Dr. Márcio Pelegrina utiliza técnicas avançadas para garantir resultados duradouros e esteticamente perfeitos.', 'Sparkles', 1),
('implantes-dentarios', 'Implantes Dentários', 'Solução definitiva para substituir dentes perdidos, garantindo estética, conforto e função mastigatória perfeitos.', 'Os implantes dentários são a solução mais moderna e eficaz para substituir dentes perdidos. O Dr. Márcio Pelegrina realiza o procedimento com precisão e tecnologia de ponta, devolvendo funcionalidade e estética ao sorriso.', 'Syringe', 2),
('tratamento-de-canal', 'Tratamento de Canal (Endodontia)', 'Tratamentos endodônticos modernos, seguros e personalizados para eliminar dores, controlar infecções e preservar seus dentes com máxima precisão.', 'O tratamento de canal é um procedimento que visa salvar dentes comprometidos por infecções ou traumas. O Dr. Márcio Pelegrina utiliza técnicas modernas e equipamentos de última geração para garantir conforto e eficácia.', 'Activity', 3),
('protese-protocolo', 'Prótese Protocolo', 'Solução fixa e estável para quem perdeu todos os dentes, devolvendo estética e funcionalidade ao sorriso.', 'A prótese protocolo é uma solução fixa sobre implantes para pacientes que perderam todos os dentes. O Dr. Márcio Pelegrina oferece reabilitação completa com materiais de alta qualidade e técnicas avançadas.', 'Users', 4),
('profilaxia-limpeza', 'Profilaxia e Raspagem (Limpeza)', 'Limpezas profissionais para manter sua saúde bucal em dia, prevenindo doenças e garantindo gengivas saudáveis.', 'A profilaxia dental é essencial para a manutenção da saúde bucal. O Dr. Márcio Pelegrina realiza limpezas profissionais completas, removendo tártaro e placa bacteriana para prevenir doenças periodontais.', 'Heart', 5),
('lentes-de-resina', 'Lentes de Resina', 'Realce seu sorriso de forma rápida e acessível com lentes de resina, conquistando estética e harmonia com procedimento minimamente invasivo.', 'As lentes de resina são uma alternativa acessível e eficaz para melhorar a estética do sorriso. O Dr. Márcio Pelegrina esculpe cada lente diretamente sobre o dente, proporcionando resultados naturais e imediatos.', 'Smile', 6),
('gengivoplastia', 'Gengivoplastia', 'Recontorno gengival para corrigir ''sorriso gengival'', nivelar margens e harmonizar o sorriso com precisão e conforto.', 'A gengivoplastia é um procedimento estético que remodela o contorno gengival para criar um sorriso mais harmonioso. O Dr. Márcio Pelegrina realiza o procedimento com técnicas minimamente invasivas para máximo conforto.', 'Scissors', 7),
('remocao-de-lentes', 'Remoção de Lentes', 'Remoção e substituição de lentes dentais com segurança, precisão e foco na saúde bucal.', 'A remoção de lentes dentais requer técnica e cuidado para preservar a estrutura dental. O Dr. Márcio Pelegrina realiza o procedimento com segurança, podendo substituir por novas lentes ou restaurar o dente natural.', 'Stethoscope', 8);